import{_ as r,C as n,o as i,c,aw as a,E as p,w as e,j as t,a as l}from"./chunks/framework.DLufY-ao.js";const d="/workbook/assets/tree1.DdPdKIqH.png",h="/workbook/assets/tree2.gTQN1FKA.jpg",u="/workbook/assets/tree3.BYNDCIp-.jpg",x=JSON.parse('{"title":"Tree (Дерево)","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/dev-commit/theory/data-structures/structures/tree.md","filePath":"wiki/dev-commit/theory/data-structures/structures/tree.md"}'),b={name:"wiki/dev-commit/theory/data-structures/structures/tree.md"};function g(y,s,m,F,k,A){const o=n("v-two");return i(),c("div",null,[s[2]||(s[2]=a('<h1 id="tree-дерево" tabindex="-1">Tree (Дерево) <a class="header-anchor" href="#tree-дерево" aria-label="Permalink to &quot;Tree (Дерево)&quot;">​</a></h1><h2 id="информация" tabindex="-1">Информация <a class="header-anchor" href="#информация" aria-label="Permalink to &quot;Информация&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">INFO</p><ul><li><a href="https://www.youtube.com/watch?v=wtgLQE9hjuk" target="_blank" rel="noreferrer">https://www.youtube.com/watch?v=wtgLQE9hjuk</a> - [YouTube] Алгоритмы и структуры данных. Деревья</li></ul></div><div class="tip custom-block"><p class="custom-block-title">Деревья</p><ul><li><strong>Деревья</strong> - эмулирует древовидную структуру в виде набора связанных узлов (вершин) и ребер</li><li>Дерево должно начинаться с единственного родителя, «корня» дерева</li><li>Дерево считается ориентированным, если в корень не заходит ни одно ребро</li><li><em>Определяющее свойство дерева</em> - существование только одного пути, соединяющего любые два узла</li></ul></div><div class="tip custom-block"><p class="custom-block-title">Двоичные деревья поиска</p><ul><li><strong>Двоичные деревья поиска</strong> позволяют быстро находить, добавлять и удалять элементы. Они устроены так, что время каждой операции пропорционально логарифму общего числа элементов в дереве</li></ul></div><h2 id="определения" tabindex="-1">Определения <a class="header-anchor" href="#определения" aria-label="Permalink to &quot;Определения&quot;">​</a></h2>',6)),p(o,{fix:""},{first:e(()=>[...s[0]||(s[0]=[t("img",{src:d,width:"200px"},null,-1)])]),last:e(()=>[...s[1]||(s[1]=[t("ul",null,[t("li",null,[t("strong",null,"Вершина (узел)"),l(" - простой объект")]),t("li",null,[t("strong",null,"Ребро"),l(" - связь между двумя верщинами")]),t("li",null,[t("strong",null,"Путь в дереве"),l(" - список отдельных вершин, в котором следующие друг за другом вершины соединяются ребрами дерева")]),t("li",null,[t("strong",null,"Корневой узел"),l(" - самый верхний узел дерева (узел 8 на примере)")]),t("li",null,[t("strong",null,"Корень"),l(" - одна из вершин, по желанию наблюдателя")]),t("li",null,[t("strong",null,"Лист, листовой или терминальный узел"),l(" - узел, не имеющий дочерних элементов (узлы 1, 4, 7, 13)")]),t("li",null,[t("strong",null,"Внутренний узел"),l(" - любой узел дерева, имеющий потомков, и таким образом, не являющийся листовым узлом (3, 6, 10, 14)")])],-1)])]),_:1}),s[3]||(s[3]=a('<h2 id="представление-дерева" tabindex="-1">Представление дерева <a class="header-anchor" href="#представление-дерева" aria-label="Permalink to &quot;Представление дерева&quot;">​</a></h2><img src="'+h+'" width="400px"><h2 id="операции" tabindex="-1">Операции <a class="header-anchor" href="#операции" aria-label="Permalink to &quot;Операции&quot;">​</a></h2><h3 id="общие-операции" tabindex="-1">Общие операции <a class="header-anchor" href="#общие-операции" aria-label="Permalink to &quot;Общие операции&quot;">​</a></h3><ul><li>Вставка нового элемента в определённую позицию</li><li>Вставка поддерева</li><li>Добавление ветви дерева</li><li>Нахождение корневого элемента для любого узла</li><li>Нахождение наименьшего общего предка двух вершин</li><li>Перебор всех элементов дерева</li><li>Перебор элементов ветви дерева</li><li>Поиск изоморфного поддерева</li><li>Поиск элемента;</li><li>Удаление ветви дерева</li><li>Удаление поддерева</li><li>Удаление элемента</li></ul><h2 id="обход-дерева" tabindex="-1">Обход дерева <a class="header-anchor" href="#обход-дерева" aria-label="Permalink to &quot;Обход дерева&quot;">​</a></h2><img src="'+u+'" width="300px"><h3 id="обход-двоичного-дерева-в-глубину-dfs-depth-first-search" tabindex="-1">Обход двоичного дерева в глубину (DFS - Depth First Search) <a class="header-anchor" href="#обход-двоичного-дерева-в-глубину-dfs-depth-first-search" aria-label="Permalink to &quot;Обход двоичного дерева в глубину (DFS - Depth First Search)&quot;">​</a></h3><blockquote><p>Используется стек</p></blockquote><ol><li>Обработка узла поддерева</li><li>Рекурсивный обход левого поддерева</li><li>Рекурсивный обход правого поддерева</li></ol><details class="details custom-block"><summary>Прямой обход (сверху-вниз, pre-order)</summary><blockquote><p>Вначале обрабатывается узел, затем посещается левое и правое поддерево</p></blockquote><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-light vp-code" tabindex="0"><code><span class="line"><span style="color:#4078F2;">E,</span><span style="color:#50A14F;"> D,</span><span style="color:#50A14F;"> B,</span><span style="color:#50A14F;"> A,</span><span style="color:#50A14F;"> C,</span><span style="color:#50A14F;"> H,</span><span style="color:#50A14F;"> F,</span><span style="color:#50A14F;"> G</span></span></code></pre></div></details><details class="details custom-block"><summary>Обратный обход (снизу вверх, post-order)</summary><blockquote><p>Вначале посещается левое и правое поддерево, затем обрабатывается узел</p></blockquote><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-light vp-code" tabindex="0"><code><span class="line"><span style="color:#4078F2;">A,</span><span style="color:#50A14F;"> C,</span><span style="color:#50A14F;"> B,</span><span style="color:#50A14F;"> D,</span><span style="color:#50A14F;"> G,</span><span style="color:#50A14F;"> F,</span><span style="color:#50A14F;"> H,</span><span style="color:#50A14F;"> E</span></span></code></pre></div></details><details class="details custom-block"><summary>Поперечный обход (слева-направо, in-order)</summary><blockquote><p>Вначале посещается левое поддерево, затем узел и правое поддерево</p></blockquote><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-light vp-code" tabindex="0"><code><span class="line"><span style="color:#4078F2;">A,</span><span style="color:#50A14F;"> B,</span><span style="color:#50A14F;"> C,</span><span style="color:#50A14F;"> D,</span><span style="color:#50A14F;"> E,</span><span style="color:#50A14F;"> F,</span><span style="color:#50A14F;"> G,</span><span style="color:#50A14F;"> H</span></span></code></pre></div></details><h3 id="обход-двоичного-дерева-в-ширину-bfs-breadth-first-search" tabindex="-1"><strong>Обход двоичного дерева в ширину (BFS - Breadth First Search)</strong> <a class="header-anchor" href="#обход-двоичного-дерева-в-ширину-bfs-breadth-first-search" aria-label="Permalink to &quot;**Обход двоичного дерева в ширину (BFS - Breadth First Search)**&quot;">​</a></h3><ul><li>Используется очередь, содержащая вершины, требующие просмотра</li><li>Выполняется по слоям начиная от корня</li></ul><p><strong>За одну итерацию алгоритма:</strong></p><ol><li>Если очередь не пуста, извлекается вершина из очереди</li><li>Обрабатывается извлеченная вершина</li><li>В очередь помещаются все дочерние</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-light vp-code" tabindex="0"><code><span class="line"><span style="color:#4078F2;">E,</span><span style="color:#50A14F;"> D,</span><span style="color:#50A14F;"> H,</span><span style="color:#50A14F;"> B,</span><span style="color:#50A14F;"> F,</span><span style="color:#50A14F;"> A,</span><span style="color:#50A14F;"> C,</span><span style="color:#50A14F;"> G</span></span></code></pre></div><h2 id="сложность-алгоритма" tabindex="-1">Сложность алгоритма <a class="header-anchor" href="#сложность-алгоритма" aria-label="Permalink to &quot;Сложность алгоритма&quot;">​</a></h2><p>Временная сложность двоичного дерева поиска</p><table tabindex="0"><thead><tr><th>Алгоритм</th><th style="text-align:right;">Среднее значение</th><th style="text-align:right;">Худший случай</th></tr></thead><tbody><tr><td>Space</td><td style="text-align:right;">O(n)</td><td style="text-align:right;">O(n)</td></tr><tr><td>Search</td><td style="text-align:right;">O(log n)</td><td style="text-align:right;">O(n)</td></tr><tr><td>Insert</td><td style="text-align:right;">O(log n)</td><td style="text-align:right;">O(n)</td></tr><tr><td>Delete</td><td style="text-align:right;">O(log n)</td><td style="text-align:right;">O(n)</td></tr></tbody></table>',21))])}const f=r(b,[["render",g]]);export{x as __pageData,f as default};
